public class TrieBasic {
    static class Trie{
        Trie[] ch=new Trie[26];boolean end;
        void insert(String w){Trie cur=this;for(char c:w.toCharArray()){int i=c-'a';if(cur.ch[i]==null)cur.ch[i]=new Trie();cur=cur.ch[i];}cur.end=true;}
        boolean search(String w){Trie cur=this;for(char c:w.toCharArray()){int i=c-'a';if(cur.ch[i]==null)return false;cur=cur.ch[i];}return cur.end;}
        boolean startsWith(String p){Trie cur=this;for(char c:p.toCharArray()){int i=c-'a';if(cur.ch[i]==null)return false;cur=cur.ch[i];}return true;}
    }
    public static void main(String[] a){
        Trie t=new Trie();t.insert("apple");
        System.out.println(t.search("apple"));   // true
        System.out.println(t.search("app"));     // false
        System.out.println(t.startsWith("app")); // true
        t.insert("app");System.out.println(t.search("app")); // true
        System.out.println("Trie: O(m) insert/search (m=word length). O(26^m) space worst.");
    }
}

