import java.util.*;
public class Autocomplete {
    static class Trie{Trie[] ch=new Trie[26];boolean end;String word;}
    static Trie root=new Trie();
    static void insert(String w){Trie c=root;for(char ch:w.toCharArray()){int i=ch-'a';if(c.ch[i]==null)c.ch[i]=new Trie();c=c.ch[i];}c.end=true;c.word=w;}
    static List<String> suggest(String prefix){List<String> res=new ArrayList<>();Trie c=root;for(char ch:prefix.toCharArray()){int i=ch-'a';if(c.ch[i]==null)return res;c=c.ch[i];}dfs(c,res);return res;}
    static void dfs(Trie n,List<String> res){if(n==null)return;if(n.end)res.add(n.word);for(Trie ch:n.ch)dfs(ch,res);}
    public static void main(String[] a){root=new Trie();for(String w:new String[]{"apple","app","application","apply","apt"})insert(w);System.out.println(suggest("app"));System.out.println(suggest("apt"));System.out.println("O(m+k) suggest: m=prefix length, k=results count");}
}

import java.util.*;
public class ReplaceWords {
    static class Trie{Trie[] ch=new Trie[26];String word;}
    static void insert(Trie root,String w){Trie c=root;for(char ch:w.toCharArray()){int i=ch-'a';if(c.ch[i]==null)c.ch[i]=new Trie();c=c.ch[i];if(c.word!=null)return;}c.word=w;}
    static String findRoot(Trie root,String w){Trie c=root;for(char ch:w.toCharArray()){int i=ch-'a';if(c.ch[i]==null)break;c=c.ch[i];if(c.word!=null)return c.word;}return w;}
    static String replaceWords(List<String> dict,String sentence){Trie root=new Trie();for(String d:dict)insert(root,d);StringBuilder sb=new StringBuilder();for(String w:sentence.split(" ")){if(sb.length()>0)sb.append(' ');sb.append(findRoot(root,w));}return sb.toString();}
    public static void main(String[] a){System.out.println(replaceWords(Arrays.asList("cat","bat","rat"),"the cattle was rattled by the battery"));System.out.println("the cat was rat by the bat");}
}

import java.util.*;
public class WordSearch2 {
    static class Trie{Trie[] ch=new Trie[26];String word;}
    static void insert(Trie root,String w){Trie c=root;for(char ch:w.toCharArray()){int i=ch-'a';if(c.ch[i]==null)c.ch[i]=new Trie();c=c.ch[i];}c.word=w;}
    static List<String> findWords(char[][] board,String[] words){
        Trie root=new Trie();for(String w:words)insert(root,w);
        Set<String> res=new HashSet<>();int m=board.length,n=board[0].length;
        for(int i=0;i<m;i++)for(int j=0;j<n;j++)dfs(board,i,j,root,res);
        return new ArrayList<>(res);}
    static void dfs(char[][] b,int r,int c,Trie node,Set<String> res){
        if(r<0||r>=b.length||c<0||c>=b[0].length||b[r][c]=='#')return;
        char ch=b[r][c];Trie next=node.ch[ch-'a'];if(next==null)return;
        if(next.word!=null)res.add(next.word);
        b[r][c]='#';dfs(b,r+1,c,next,res);dfs(b,r-1,c,next,res);dfs(b,r,c+1,next,res);dfs(b,r,c-1,next,res);b[r][c]=ch;}
    public static void main(String[] a){char[][] board={{'o','a','a','n'},{'e','t','a','e'},{'i','h','k','r'},{'i','f','l','v'}};System.out.println(findWords(board,new String[]{"oath","pea","eat","rain"}));System.out.println("Trie pruning: skip DFS when no matching prefix. O(m*n*4^L) worst.");}
}

public class WordDict {
    static class Trie{Trie[] ch=new Trie[26];boolean end;}
    static Trie root=new Trie();
    static void addWord(String w){Trie c=root;for(char ch:w.toCharArray()){int i=ch-'a';if(c.ch[i]==null)c.ch[i]=new Trie();c=c.ch[i];}c.end=true;}
    static boolean search(String w){return sH(w,0,root);}
    static boolean sH(String w,int i,Trie n){if(i==w.length())return n.end;char c=w.charAt(i);if(c=='.'){for(Trie ch:n.ch)if(ch!=null&&sH(w,i+1,ch))return true;return false;}if(n.ch[c-'a']==null)return false;return sH(w,i+1,n.ch[c-'a']);}
    public static void main(String[] a){root=new Trie();addWord("bad");addWord("dad");addWord("mad");System.out.println(search("pad"));System.out.println(search("bad"));System.out.println(search(".ad"));System.out.println(search("b.."));System.out.println("'.' matches any char — try all 26 children at that position");}
}

import java.util.*;
public class LongestWord {
    public static String longestWord(String[] words){
        Arrays.sort(words);Set<String> built=new HashSet<>();built.add("");String res="";
        for(String w:words)if(built.contains(w.substring(0,w.length()-1))){built.add(w);if(w.length()>res.length())res=w;}
        return res;
    }
    public static void main(String[] a){System.out.println(longestWord(new String[]{"w","wo","wor","worl","world"}));System.out.println(longestWord(new String[]{"a","banana","app","appl","ap","apply","apple"}));System.out.println("Sort+HashSet: add if prefix (all but last char) already in set. O(n*m log n)");}
}

import java.util.*;
public class MapSum {
    static class Trie{Trie[] ch=new Trie[26];int val;}
    static Trie root=new Trie();
    static Map<String,Integer> map=new HashMap<>();
    static void insert(String k,int v){int diff=v-map.getOrDefault(k,0);map.put(k,v);Trie c=root;for(char ch:k.toCharArray()){int i=ch-'a';if(c.ch[i]==null)c.ch[i]=new Trie();c=c.ch[i];c.val+=diff;}}
    static int sum(String prefix){Trie c=root;for(char ch:prefix.toCharArray()){int i=ch-'a';if(c.ch[i]==null)return 0;c=c.ch[i];}return c.val;}
    public static void main(String[] a){root=new Trie();map=new HashMap<>();insert("apple",3);System.out.println(sum("ap"));System.out.println(sum("b"));insert("app",2);System.out.println(sum("ap"));System.out.println("Store cumulative sum at each Trie node. O(m) insert/sum.");}
}

public class MaxXOR {
    static int[][] trie=new int[600000][2];static int tot=1;
    static void insert(int n){int cur=0;for(int i=31;i>=0;i--){int b=(n>>i)&1;if(trie[cur][b]==0)trie[cur][b]=tot++;cur=trie[cur][b];}}
    static int maxXOR(int n){int cur=0,res=0;for(int i=31;i>=0;i--){int b=(n>>i)&1,want=1-b;if(trie[cur][want]!=0){res|=(1<<i);cur=trie[cur][want];}else cur=trie[cur][b];}return res;}
    public static void main(String[] a){tot=1;for(int i=0;i<600000;i++)trie[i][0]=trie[i][1]=0;int[]nums={3,10,5,25,2,8};int max=0;for(int n:nums)insert(n);for(int n:nums)max=Math.max(max,maxXOR(n));System.out.println(max);System.out.println("28 — binary Trie for XOR max: at each bit, prefer opposite bit.");}
}

